mapper.sql:
FROM ref_sample_item WHERE deleted_yn = 'N'
AND ( LOWER(item_name) LIKE CONCAT('%', LOWER(#{criteria.keyword}), '%') OR LOWER(category_code) LIKE CONCAT('%', LOWER(#{criteria.keyword}), '%') )
AND status_code = #{criteria.statusCode}

mapper.select:
SELECT

FROM ref_sample_item
WHERE deleted_yn = 'N'

  AND sample_item_id > #{criteria.cursorId}

ORDER BY sample_item_id ASC
LIMIT #{criteria.limit}
